import { GeoScatterSeries } from '../geo-scatter/geo-scatter';
import { inherit } from '../utils/zcutils';
import { maps } from '../core/chart-instance-manager';

/**
 *
 * @param series
 * @param geoMap
 * @param index
 * @constructor
 */
export function GeoBubbleSeries(series, geoMap, index) {
    GeoScatterSeries.call(this, series, geoMap, index);
}

// inherit from MapSeries
inherit(GeoBubbleSeries, GeoScatterSeries);

// add HeatMapSeries to global holder
maps.GeoMap.SeriesTypes.set('geobubble', GeoBubbleSeries);
